export const glossary: GlossaryTerm[] = [
  { term: 'ML Systems Engineering', definition: 'The holistic discipline of designing, building, and maintaining production ML systems across all layers of the stack.' },
  { term: 'Trade-off Analysis', definition: 'The systematic evaluation of competing design objectives to find the best balance for a specific application.' },
  { term: 'Production ML', definition: 'Machine learning systems deployed in real-world applications serving actual users, as opposed to research prototypes.' },
  { term: 'Technical Debt', definition: 'The accumulated cost of shortcuts and suboptimal decisions that increase future maintenance burden.' },
  { term: 'Continuous Learning', definition: 'The ongoing practice of staying current with new developments, tools, and best practices in the rapidly evolving ML field.' },
  { term: 'Neuromorphic Computing', definition: 'A computing paradigm inspired by the brain\'s neural architecture that co-locates memory and computation, offering dramatic energy efficiency for event-driven ML workloads.' },
  { term: 'Federated Learning', definition: 'A distributed ML training approach where models are trained across decentralized data sources without centralizing the raw data, preserving privacy.' },
  { term: 'AI Alignment', definition: 'The research and engineering challenge of ensuring that AI systems behave in accordance with human values and intentions.' },
  { term: 'Foundation Model', definition: 'A large model trained on broad data that can be adapted (fine-tuned or prompted) for a wide range of downstream tasks.' },
  { term: 'Quantum Machine Learning', definition: 'The intersection of quantum computing and ML, exploring whether quantum processors can offer computational advantages for learning tasks.' },
  { term: 'T-Shaped Skills', definition: 'A career development strategy combining broad knowledge across ML systems (horizontal bar) with deep expertise in one or two specializations (vertical bar).' },
  { term: 'Synthetic Data', definition: 'Artificially generated data used for training ML models when real data is scarce, sensitive, or expensive to collect, with growing importance in privacy-sensitive domains.' },
  { term: 'Edge AI', definition: 'Running ML inference on local devices (phones, IoT, embedded systems) rather than in the cloud, enabling lower latency, offline operation, and data privacy.' },
];

export const keyTakeaways: string[] = [
  'ML systems engineering is a holistic discipline requiring knowledge across algorithms, hardware, software, data, and operations.',
  'Trade-off management between competing objectives -- accuracy vs. latency, privacy vs. utility, cost vs. quality -- is the most important skill in ML systems design.',
  'The full lifecycle perspective, from data to deployment to monitoring, determines real-world system success; the model is only about 5% of a production ML system.',
  'Responsible engineering that considers fairness, security, privacy, and sustainability is a core requirement, not an optional extra.',
  'Career paths span ML Engineering, MLOps, Research Science, and AI Safety -- T-shaped skills combining breadth with deep specialization are most effective.',
  'Emerging technologies like neuromorphic computing, federated learning at scale, and ML compilers will reshape the field by 2030.',
  'Essential papers (Attention Is All You Need, Chinchilla, Hidden Technical Debt) and hands-on open-source contributions are the foundation of continuous learning.',
  'Continuous learning through hands-on practice, community engagement, and staying current with research is essential in this rapidly evolving field.',
  'The ultimate measure of an ML systems engineer is not technical sophistication but the benefit their systems bring to the people they serve.',
];

